import scala.xml._
import scala.io.Source

case class Setting(key: String, value: String)

object ConfigService {
  val defaultEntities = Map(
    "app" -> """<app id="1">Some Default Value</app>""",
    // Add more entities as needed
  )

  def loadConfig(xmlString: String): List[Setting] = {
    val entities = defaultEntities ++ parseEntities(xmlString)
    parseSettings(loadXML(xmlString, entities))
  }

  private def loadXML(xmlString: String, entities: Map[String, Node]): Node = {
    val expandedXml = expandEntities(xmlString, entities)
    scala.xml.XML.loadString(expandedXml)
  }

  private def parseEntities(xmlString: String): Map[String, Node] = {
    // Parse entity declarations from the XML string and return a map of entities to their corresponding nodes
    // This is just an example implementation, you may need to adjust it based on your actual XML structure
    val regex = """&([a-zA-Z0-9]+);""".r
    xmlString.split("&").zipWithIndex.flatMap { case (part, index) =>
      if (regex.findFirstMatchIn(part).nonEmpty) {
        Some((index match { case 1 => regex(part).group(1) case _ => "" }, entities(regex(part).group(1))))
      } else None
    }.toMap ++ defaultEntities
  }

  private def expandEntities(xmlString: String, entities: Map[String, Node]): String = {
    val regex = """&([a-zA-Z0-9]+);""".r
    xmlString replaceAllLiterally(regex.findAllMatchIn(xmlString).map(m => entities(m.group(1)).text).mkString)
  }

  private def parseSettings(config: Node): List[Setting] = {
    // Parse settings from the loaded XML and return a list of Settings objects
    (config \ "setting").map { settingNode =>
      val key = (settingNode \ "@key").text
      val value = (settingNode \ "*").text
      Setting(key, value)
    }.toList
  }
